import{c as o,Q as a,j as d,m as i}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Идеи","description":"","frontmatter":{},"headers":[],"relativePath":"ru/ideas.md","filePath":"ru/ideas.md","lastUpdated":1781982620000}'),c={name:"ru/ideas.md"};function r(l,e,s,t,n,u){return a(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="идеи" tabindex="-1">Идеи <a class="header-anchor" href="#идеи" aria-label="Permalink to &quot;Идеи&quot;">​</a></h1><p>Эта страница хранит крупные идеи и продуктовые заметки по рабочим процессам. Часть идей уже может иметь первую реализацию, а следующие расширения остаются экспериментальными. Это не обещание коммерческого продукта и не research benchmark; цель страницы — объяснить направление и текущие ограничения.</p><h2 id="smart-set-builder-по-seed-трекам" tabindex="-1">Smart Set Builder по seed-трекам <a class="header-anchor" href="#smart-set-builder-по-seed-трекам" aria-label="Permalink to &quot;Smart Set Builder по seed-трекам&quot;">​</a></h2><p>Первая версия Smart Set Builder добавляет вкладку SET, которая генерирует упорядоченный DJ set preview из <code>1-5</code> manual seed-треков или <code>1-5</code> случайных, но связанных auto anchors, выбранных backend при каждом запуске. Цель — не просто найти &quot;ещё похожие треки&quot;, а собрать последовательность для прослушивания, digging или подготовки сета.</p><p>Seed-треки здесь означают треки, выбранные как отправная точка: например, &quot;вот такой грув&quot;, &quot;вот такая темнота&quot;, &quot;вот такой break&quot;, &quot;вот такая абстрактная фактура&quot;. Auto mode делает то же самое без ручного выбора: система сама семплирует связанные anchors из треков, у которых есть полный набор нужных признаков.</p><h2 id="первая-версия-без-новои-модели" tabindex="-1">Первая версия без новой модели <a class="header-anchor" href="#первая-версия-без-новои-модели" aria-label="Permalink to &quot;Первая версия без новой модели&quot;">​</a></h2><p>Первая версия не обучает новую модель. Она комбинирует уже сохранённые сигналы:</p><ul><li>MERT similarity для музыкальной и аудиальной близости.</li><li>MAEST embeddings для дополнительного audio-model agreement.</li><li>CLAP audio embeddings из сохранённого анализа; текстовый prompt в SET v1 не используется.</li><li>Широкий блок SONARA features: rhythm/tempo, dynamics, perception, tonal texture, spectral/timbre values и сохранённые summary statistics для больших массивов вроде MFCC/chroma.</li><li>Promoted classifier scores, например <code>abstract_edge</code>, <code>break_energy</code> или <code>voice_presence</code>, как необязательные target, avoid или mood-curve сигналы.</li><li>BPM/key из file tags, а при их отсутствии SONARA fallback, как мягкий сигнал порядка переходов, плюс опциональные явные BPM-траектории для slow-to-fast или fast-to-slow сетов.</li></ul><p>MAEST genre labels специально не используются для выбора треков. SET может использовать MAEST embeddings, но не должен подменять similarity жанровыми лейблами.</p><h2 id="как-работает-auto-mode" tabindex="-1">Как работает auto mode <a class="header-anchor" href="#как-работает-auto-mode" aria-label="Permalink to &quot;Как работает auto mode&quot;">​</a></h2><p>В auto mode backend не берёт один и тот же фиксированный набор треков навсегда. Каждый запуск выбирает <code>1-5</code> random related anchors из feature-complete треков. Anchors должны быть связаны между собой и с выбранным режимом, но выбор остаётся случайным, поэтому повторный запуск может дать другой сет.</p><p>После выбора anchors алгоритм строит кандидатный pool по MERT, MAEST, CLAP и SONARA similarity, применяет mode-specific scoring, diversity, classifier signals, мягкую совместимость BPM/key и правила артиста. Затем он упорядочивает preview как DJ-последовательность. API-only поле <code>random_seed</code> можно передать только если нужно воспроизвести конкретный randomized run.</p><h2 id="режимы" tabindex="-1">Режимы <a class="header-anchor" href="#режимы" aria-label="Permalink to &quot;Режимы&quot;">​</a></h2><h3 id="similar-crate-similar-crate-close" tabindex="-1"><code>similar_crate</code> (<code>Similar crate - close</code>) <a class="header-anchor" href="#similar-crate-similar-crate-close" aria-label="Permalink to &quot;`similar_crate` (`Similar crate - close`)&quot;">​</a></h3><p>Режим близкой подборки. Он держится рядом с seed/anchor зоной и сильнее ценит согласие MERT, CLAP, MAEST embeddings и SONARA similarity.</p><p>Пояснение: это режим &quot;дай мне ящик похожего материала&quot;. Он нужен, когда исходная зона уже правильная и хочется меньше риска.</p><h3 id="weird-adjacent-weird-adjacent-odd" tabindex="-1"><code>weird_adjacent</code> (<code>Weird adjacent - odd</code>) <a class="header-anchor" href="#weird-adjacent-weird-adjacent-odd" aria-label="Permalink to &quot;`weird_adjacent` (`Weird adjacent - odd`)&quot;">​</a></h3><p>Режим странных, но релевантных соседей. Он сохраняет связь с anchors, но разрешает больше бокового движения по фактуре, classifier signals и model disagreement.</p><p>Пояснение: такой трек может быть не очевидным клоном seed-трека, а полезным переходом в соседнюю музыкальную область.</p><h3 id="balanced-set-balanced-set-flow" tabindex="-1"><code>balanced_set</code> (<code>Balanced set - flow</code>) <a class="header-anchor" href="#balanced-set-balanced-set-flow" aria-label="Permalink to &quot;`balanced_set` (`Balanced set - flow`)&quot;">​</a></h3><p>DJ-ориентированный режим. Он балансирует similarity, diversity, bridge-треки, BPM/key переходы, energy curve и ограничения по исполнителям.</p><p>Пояснение: здесь важен не только выбор отдельных хороших кандидатов, но и их порядок. Два трека могут быть хорошими отдельно, но плохо работать рядом из-за энергии, темпа или слишком похожей фактуры.</p><h3 id="discovery-discovery-wide" tabindex="-1"><code>discovery</code> (<code>Discovery - wide</code>) <a class="header-anchor" href="#discovery-discovery-wide" aria-label="Permalink to &quot;`discovery` (`Discovery - wide`)&quot;">​</a></h3><p>Режим более широкого поиска. Он даёт больше novelty/diversity и допускает рискованные кандидаты, но всё ещё подчиняется anchors и выбранным правилам.</p><p>Пояснение: это режим &quot;покажи полезные гипотезы&quot;, особенно когда пользователь ищет новые positives для будущих classifier-профилей.</p><h2 id="ui-controls" tabindex="-1">UI controls <a class="header-anchor" href="#ui-controls" aria-label="Permalink to &quot;UI controls&quot;">​</a></h2><p>Текущая вкладка SET подписывает каждую основную настройку:</p><ul><li><code>Seed source</code>: <code>Manual - selected</code> использует выбранные seed chips; <code>Auto - random related</code> каждый запуск выбирает новые связанные anchors.</li><li><code>Set mode</code>: выбирает один из режимов выше.</li><li><code>Track limit</code>: длина preview, по умолчанию <code>24</code>; seed/anchor позиции входят в этот лимит.</li><li><code>Auto anchors</code>: сколько random related anchors брать в auto mode, <code>1-5</code>.</li><li><code>Energy curve</code>: <code>Balanced - steady</code>, <code>Warmup - build</code>, <code>Peak - intense</code> или <code>Wave - rise/fall</code>.</li><li><code>Diversity</code>: <code>0.00-1.00</code>; ниже = ближе к anchors, выше = шире подборка при сохранении режима.</li><li><code>BPM mode</code>: <code>General BPM - transition</code>, <code>Low to high - climb</code> или <code>High to low - descend</code>.</li><li><code>BPM change</code>: slow, medium или fast движение темпа по preview.</li><li><code>Start BPM</code> и <code>Target BPM</code>: необязательные явные границы темпа; пустые значения выводятся из первого seed/anchor и BPM-диапазона библиотеки.</li><li>Classifier sliders: <code>Target boost</code>, <code>Avoid cut</code>, <code>Curve start</code>, <code>Curve end</code>.</li><li><code>Reset sliders</code>: сбрасывает только <code>Diversity</code> и classifier sliders; seed source, mode, limit, auto anchors, energy curve и BPM controls не меняются.</li></ul><h2 id="объяснимыи-результат" tabindex="-1">Объяснимый результат <a class="header-anchor" href="#объяснимыи-результат" aria-label="Permalink to &quot;Объяснимый результат&quot;">​</a></h2><p>Сгенерированный результат объясняет, почему каждый трек попал в список. Например:</p><ul><li><code>seed_anchor</code>: manual seed или auto anchor.</li><li><code>similar_to_seed</code>: трек близок к одному или нескольким anchors.</li><li><code>bridge</code>: трек может связывать разные зоны или соседние части списка.</li><li><code>weird_adjacent</code>: трек не очевидно похож, но находится рядом по важным признакам.</li><li><code>discovery</code>: трек выбран как более широкая гипотеза.</li><li><code>classifier_match</code>: трек выбран из-за совпадения с promoted classifier.</li><li><code>mood_shift</code>: трек помогает двигать classifier или energy curve.</li></ul><p>Preview также показывает model scores, SONARA group scores, classifier scores и transition metadata. Это нужно, чтобы пользователь мог быстро понять причину выбора, оставить трек, удалить его или отправить на дальнейшую разметку.</p><p>Ограничение по исполнителям строгое: один известный исполнитель может появиться в одном SET preview максимум один раз. Manual seeds остаются отмеченными как <code>seed_anchor</code>, но повтор известного исполнителя среди manual seeds отклоняется.</p><h2 id="api-shape" tabindex="-1">API shape <a class="header-anchor" href="#api-shape" aria-label="Permalink to &quot;API shape&quot;">​</a></h2><p>Текущий endpoint:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /api/set-builder/generate</span></span></code></pre></div><p>Поля входа:</p><ul><li><code>seed_mode</code>: <code>manual</code> или <code>auto</code>.</li><li><code>seed_track_ids</code>: <code>1-5</code> manual seed IDs.</li><li><code>auto_seed_count</code>: <code>1-5</code> anchors для auto mode.</li><li><code>limit</code>: длина preview.</li><li><code>mode</code>: <code>similar_crate</code>, <code>weird_adjacent</code>, <code>balanced_set</code> или <code>discovery</code>.</li><li><code>diversity</code>: насколько сильно разрешено отходить от anchor зоны.</li><li><code>energy_curve</code>: <code>warmup</code>, <code>balanced</code>, <code>peak</code> или <code>wave</code>.</li><li><code>bpm_mode</code>: <code>general</code>, <code>low_to_high</code> или <code>high_to_low</code>.</li><li><code>bpm_change</code>: <code>slow</code>, <code>medium</code> или <code>fast</code>.</li><li><code>bpm_start</code>: необязательный явный стартовый BPM.</li><li><code>bpm_target</code>: необязательный явный целевой BPM.</li><li><code>classifier_targets</code>: какие promoted classifier scores считать желательными.</li><li><code>classifier_avoid</code>: какие promoted classifier scores считать нежелательными.</li><li><code>classifier_curves</code>: start/end target intensity для promoted classifiers.</li><li><code>random_seed</code>: необязательное API-only поле для воспроизведения одного randomized run.</li></ul><p>Поля выхода:</p><ul><li>ordered track rows;</li><li>selection reason;</li><li>similarity, SONARA group, transition, classifier и diversity scores;</li><li>relevant classifier scores;</li><li>transition metadata для порядка сета.</li></ul><h2 id="возможные-расширения-позже" tabindex="-1">Возможные расширения позже <a class="header-anchor" href="#возможные-расширения-позже" aria-label="Permalink to &quot;Возможные расширения позже&quot;">​</a></h2><p>После первой версии можно добавить:</p><ul><li>отправку выбранных треков в Rhythm Lab;</li><li>отметку кандидатов как reviewed;</li><li>экспорт XLSX lists;</li><li>исключение уже reviewed/exported кандидатов;</li><li>сохранение sessions генерации;</li><li>iterative active-learning workflow, где пользователь слушает кандидатов, размечает удачные и постепенно улучшает promoted classifiers.</li></ul><p>Пояснение: это превращает генератор списков в рабочий цикл. Сначала система предлагает кандидатов, потом пользователь проверяет их, а затем эти решения становятся данными для следующих classifier-профилей и будущих подборок.</p>',44)])])}const p=o(c,[["render",r]]);export{m as __pageData,p as default};
